module freq_div(
    input CLK_in,
    input RST,
    output CLK_50,
    output CLK_10,
    output CLK_1
);

reg [2:0] counter_50;
reg [3:0] counter_10;
reg [6:0] counter_1;
reg clk_50, clk_10, clk_1;

always @(posedge CLK_in or negedge RST) begin
    if (!RST) begin
        counter_50 <= 0;
        counter_10 <= 0;
        counter_1 <= 0;
        clk_50 <= 0;
        clk_10 <= 0;
        clk_1 <= 0;
    end
    else begin
        if (counter_50 == 4) begin
            counter_50 <= 0;
            clk_50 <= ~clk_50;
        end
        else begin
            counter_50 <= counter_50 + 1;
        end

        if (counter_10 == 9) begin
            counter_10 <= 0;
            clk_10 <= ~clk_10;
        end
        else begin
            counter_10 <= counter_10 + 1;
        end

        if (counter_1 == 99) begin
            counter_1 <= 0;
            clk_1 <= ~clk_1;
        end
        else begin
            counter_1 <= counter_1 + 1;
        end
    end
end

assign CLK_50 = clk_50;
assign CLK_10 = clk_10;
assign CLK_1 = clk_1;

endmodule
